import React from 'react';
import { useNavigate } from 'react-router-dom';
import JobCard from '../components/JobCard';
import useFetchJobs from '../hooks/useFetchJobs';
import LoadingSpinner from '../components/LoadingSpinner';

const HomePage = () => {
  const navigate = useNavigate();
  const { jobs, loading, error } = useFetchJobs();

  const handleSearch = () => {
    navigate('/jobs');
  };

  return (
    <div className="bg-gray-950 text-white">
      <section className="relative bg-gray-950 text-white overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-900/30 via-gray-950 to-gray-950 pointer-events-none" />
        <div className="relative max-w-6xl mx-auto px-4 py-24 flex flex-col items-center text-center gap-6">
          <h1 className="text-4xl md:text-6xl font-bold tracking-tight leading-tight max-w-3xl">
            Find Your Dream Job
          </h1>
          <p className="text-gray-400 text-lg max-w-xl leading-relaxed">
            Search and apply for jobs from top companies worldwide.
          </p>
          <button
            onClick={handleSearch}
            className="px-6 py-3 rounded-xl bg-indigo-600 text-white font-medium hover:bg-indigo-500 transition-colors shadow-lg shadow-indigo-900/40"
          >
            Search Jobs
          </button>
        </div>
      </section>
      <section className="py-16 bg-gray-900">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-2xl font-semibold text-white mb-2">Featured Jobs</h2>
          <p className="text-gray-400 mb-10">Explore top job opportunities.</p>
          {loading ? (
            <LoadingSpinner />
          ) : error ? (
            <p className="text-red-500">Failed to load jobs. Please try again later.</p>
          ) : jobs.length === 0 ? (
            <p className="text-gray-400">No jobs available at the moment.</p>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {jobs.map(job => (
                <JobCard key={job.id} job={job} />
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default HomePage;

