import React, { useState } from 'react';
import JobCard from '../components/JobCard';
import useFetchJobs from '../hooks/useFetchJobs';
import LoadingSpinner from '../components/LoadingSpinner';

const JobListPage = () => {
  const { jobs, loading, error } = useFetchJobs();
  const [searchTerm, setSearchTerm] = useState('');

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchTerm(e.target.value);
  };

  const filteredJobs = jobs.filter(job =>
    job.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-gray-950 text-white min-h-screen">
      <div className="max-w-6xl mx-auto px-4 py-16">
        <h1 className="text-3xl font-bold mb-6">Job Listings</h1>
        <input
          type="text"
          value={searchTerm}
          onChange={handleSearchChange}
          placeholder="Search jobs..."
          className="w-full p-4 mb-6 rounded-xl bg-gray-800 text-white placeholder-gray-400"
        />
        {loading ? (
          <LoadingSpinner />
        ) : error ? (
          <p className="text-red-500">Failed to load jobs. Please try again later.</p>
        ) : filteredJobs.length === 0 ? (
          <p className="text-gray-400">No jobs match your search criteria.</p>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
            {filteredJobs.map(job => (
              <JobCard key={job.id} job={job} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default JobListPage;

