import React from 'react';
import { useParams } from 'react-router-dom';
import useFetchJobs from '../hooks/useFetchJobs';
import LoadingSpinner from '../components/LoadingSpinner';

const JobDetailPage = () => {
  const { jobId } = useParams<{ jobId: string }>();
  const { jobs, loading, error } = useFetchJobs();
  const job = jobs.find(j => j.id === jobId);

  if (loading) return <LoadingSpinner />;
  if (error) return <p className="text-red-500">Failed to load job details. Please try again later.</p>;
  if (!job) return <p className="text-gray-400">Job not found.</p>;

  return (
    <div className="bg-gray-950 text-white min-h-screen">
      <div className="max-w-6xl mx-auto px-4 py-16">
        <h1 className="text-3xl font-bold mb-4">{job.title}</h1>
        <p className="text-gray-400 mb-4">{job.company}</p>
        <p className="text-gray-400 mb-4">{job.location}</p>
        <p className="text-gray-400 mb-4">{job.description}</p>
        <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
          Apply Now
        </button>
      </div>
    </div>
  );
};

export default JobDetailPage;
